import{_ as o,C as n,o as s,c as i,j as e,a as r,E as a,a2 as c}from"./chunks/framework.fDPUq4J2.js";const R=JSON.parse('{"title":"Error Codes","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/error-codes.md","filePath":"implementation/error-codes.md","lastUpdated":1779360052000}'),l={name:"implementation/error-codes.md"},p={id:"error-codes",tabindex:"-1"};function u(h,t,E,g,f,T){const d=n("Badge");return s(),i("div",null,[e("h1",p,[t[0]||(t[0]=r("Error Codes ",-1)),a(d,{type:"warning",text:"Since 1.0.0-alpha.13"}),t[1]||(t[1]=r()),t[2]||(t[2]=e("a",{class:"header-anchor",href:"#error-codes","aria-label":'Permalink to "Error Codes <Badge type="warning" text="Since 1.0.0-alpha.13"/>"'},"​",-1))]),t[3]||(t[3]=c('<p>The following table lists the error codes used in the TORCH system. Each error code is unique and provides information about the type of error, its severity, and recommended actions for users and developers.</p><p>Error Code – A unique identifier for the error, structured as MODULE_SUBMODULE_NUMBER.</p><p>Meaning – A brief description of the error and its context.</p><p>Severity – Indicates the impact of the error (Info, Warning, Error, Critical).</p><p>User Action / Fix – Recommended steps the end user can take to resolve the issue.</p><p>Developer Notes – Additional technical information for developers to troubleshoot and address the error.</p><p>This table is intended to support both end users and developers in quickly identifying, diagnosing, and resolving issues encountered in the system.</p><table tabindex="0"><thead><tr><th>Error Code</th><th>Meaning</th><th>Severity</th><th>User Action / Fix</th><th>Developer Notes</th></tr></thead><tbody><tr><td>RESULT_01</td><td>Could not create results directory</td><td>Error</td><td>Check directory path and permissions</td><td>Thrown when <code>Files.createDirectories</code> fails in constructor</td></tr><tr><td>RESULT_02</td><td>Results directory is not writable</td><td>Error</td><td>Adjust filesystem permissions</td><td>Triggered when directory exists but is not writable</td></tr><tr><td>RESULT_03</td><td>Error reading job directory</td><td>Warning</td><td>None; system will skip unreadable directory</td><td>Happens when listing or reading a job directory fails</td></tr><tr><td>RESULT_04</td><td>Error loading existing results</td><td>Warning</td><td>None; system continues but previous jobs may be missing</td><td>Thrown when scanning the results root directory fails</td></tr><tr><td>RESULT_05</td><td>Async write failed for job error file</td><td>Error</td><td>Retry operation or inspect logs</td><td>Indicates failure inside async <code>saveErrorToJson</code> write operation</td></tr><tr><td>RESULT_06</td><td>Failed to load bundles for job</td><td>Warning</td><td>Inspect job directory structure</td><td>Thrown when listing files in a job directory for output generation fails</td></tr><tr><td>CONSENT_VALIDATOR_01</td><td>A Resource was loaded that does not belong to any Patient belonging to the batch</td><td>Warning</td><td>Manually check if resource is referenced by a resource belonging to another patient</td><td>Thrown due to referenced Patient not being part of the batch from which the resource was loaded</td></tr><tr><td>CONSENT_VALIDATOR_02</td><td>Consent check was done on an unsupported ResourceType</td><td>Warning</td><td>Contact developers if it is a patient resource type that should be supported</td><td>Thrown due to resource type not being in the resourceType to field mapping for consent</td></tr><tr><td>FHIR_CONTROLLER_01</td><td>Bad Request received</td><td>Error</td><td>Fix Parameters File or CRTDL</td><td>Thrown due to input validation or parsing fail</td></tr><tr><td>FHIR_CONTROLLER_02</td><td>Some internal server error i.e. the complete extraction crashed</td><td>Error</td><td>Inspect logs and contact developers for potential bugs</td><td>Thrown due to resource type not being in the resourceType to field mapping for consent</td></tr><tr><td>FHIR_CONTROLLER_03</td><td>Trying to look up error status failed</td><td>Error</td><td>Retry operation or inspect logs</td><td>Thrown due error job status existing but no error operation outcome found in dir</td></tr><tr><td>DATASTORE_01</td><td>FHIR server returned an OperationOutcome during search</td><td>Error</td><td>Inspect OperationOutcome details and fix query parameters</td><td>Logged when executing .search() and an OperationOutcome is returned instead of a Bundle</td></tr><tr><td>DATASTORE_02</td><td>Error executing resource query (search)</td><td>Error</td><td>Retry or inspect server availability and feasibility query syntax</td><td>Logged in .search() in doOnError, wraps any exception during search</td></tr><tr><td>DATASTORE_03</td><td>Error executing a transaction</td><td>Error</td><td>Retry; if persistent, review the transaction bundle</td><td>Logged in .transact() when POST / fails</td></tr><tr><td>DATASTORE_04</td><td>Error evaluating a Measure</td><td>Error</td><td>Inspect the Measure parameter set; retry; contact developers if persists</td><td>Logged in .evaluateMeasure() when sync or async-polling evaluation fails</td></tr><tr><td>DATASTORE_05</td><td>Unexpected resource type returned during polling</td><td>Error</td><td>Contact developers; fix FHIR endpoint returning unexpected structure</td><td>Happens in async poll response mapping in .pollStatus() when resource is not MeasureReport or unknown</td></tr><tr><td>DATASTORE_06</td><td>Missing Content-Location header for async operation</td><td>Error</td><td>Retry operation; report misconfigured FHIR server</td><td>Thrown in MissingContentLocationException when server returns 202 without a status URL</td></tr><tr><td>DATASTORE_07</td><td>Async polling missing response or outcome field</td><td>Error</td><td>Contact developers; server likely misbehaving</td><td>From .pollStatus() when bundle entry response fields are unexpectedly missing</td></tr><tr><td>DATASTORE_08</td><td>Error deserializing FHIR JSON payload</td><td>Error</td><td>Verify FHIR server output; ensure correct FHIR version</td><td>Thrown from parseResource() on DataFormatException</td></tr><tr><td>DATASTORE_09</td><td>Unexpected resource type in batch search response</td><td>Warning</td><td>None required; system ignores unexpected resources</td><td>Logged in extractResourcesFromBundle() when resource is not a Bundle</td></tr><tr><td>DATASTORE_10</td><td>Batch Bundle Search failed in Reference Resolve</td><td>Error</td><td>None required; Results in references not being resolved/handled</td><td>Thrown due to error in bundle search</td></tr><tr><td>PROCESSING_01</td><td>Response Error from CQL Execution</td><td>Error</td><td>Retry operation or inspect logs</td><td>Thrown due to CRTDL error</td></tr><tr><td>PROCESSING_02</td><td>Error from Flare Execution</td><td>Error</td><td>Retry operation or inspect logs</td><td>Thrown due to Flare error</td></tr><tr><td>RESOURCE_REFLECTION_01</td><td>Method Error when setting Backbone Element</td><td>Error</td><td>Contact developers;</td><td>Thrown by setting backbone Element</td></tr><tr><td>RESOURCE_REFLECTION_02</td><td>Backbone Element is not a known HAPI Class</td><td>Error</td><td>Contact developers;</td><td>Thrown by setting backbone Element</td></tr><tr><td>REDACTION_01</td><td>Requested Profiles not found after Extraction despite copying meta and validation</td><td>Error</td><td>Contact developers;</td><td></td></tr><tr><td>REDACTION_02</td><td>Requested Profiles not known despite validation</td><td>Error</td><td>Check if ontology is mounted and was modified. Contact developers;</td><td></td></tr></tbody></table>',8))])}const m=o(l,[["render",u]]);export{R as __pageData,m as default};
